const doc = $input.first().json;

const result = [];

// Loop through all tabs
const tabs = doc.tabs || [];

for (const tab of tabs) {
  const tabName = tab.documentTab?.properties?.title || "Untitled";
  const bodyContent = tab.documentTab?.body?.content || [];
  const tabData = { tab: tabName };

  for (const element of bodyContent) {
    if (!element.table) continue;

    for (const row of element.table.tableRows || []) {
      const cells = row.tableCells || [];
      if (cells.length < 2) continue;

      const getCellText = (cell) => {
        return (cell.content || [])
          .flatMap(c => c.paragraph?.elements || [])
          .map(el => el?.textRun?.content || "")
          .join("")
          .trim();
      };

      const key = getCellText(cells[0]);
      let value = getCellText(cells[1]);

      if (!key) continue;

      if (value.startsWith("Subject:")) {
        const firstNewline = value.indexOf("\n");
        tabData[key] = {
          subject: value.slice(0, firstNewline).replace("Subject:", "").trim(),
          body: value.slice(firstNewline).trim()
        };
      } else {
        tabData[key] = value;
      }
    }
  }

  result.push({ json: tabData });
}

return result;
